import React, { useState, useEffect } from 'react';
import { Stage, Layer } from 'react-konva';
import Spaceship from './Spaceship';
import Background from './Background';
import Bullet from './Bullet';

const Game = () => {
    const [spaceshipPosition, setSpaceshipPosition] = useState({ x: window.innerWidth / 2, y: window.innerHeight - 60 });
    const [bullets, setBullets] = useState([]);

    const handleKeyDown = (e) => {
        if (e.key === 'ArrowLeft') {
            setSpaceshipPosition((pos) => ({ ...pos, x: pos.x - 10 }));
        } else if (e.key === 'ArrowRight') {
            setSpaceshipPosition((pos) => ({ ...pos, x: pos.x + 10 }));
        } else if (e.key === ' ') {
            // Mermi ateş etme mekanizması
            setBullets((prevBullets) => [
                ...prevBullets,
                { x: spaceshipPosition.x + 22.5, y: spaceshipPosition.y }, // Uzay gemisinin ortasına yerleştir
            ]);
        }
    };

    useEffect(() => {
        window.addEventListener('keydown', handleKeyDown);
        return () => {
            window.removeEventListener('keydown', handleKeyDown);
        };
    }, []);

    // Mermileri yukarı hareket ettirmek için bir efekt
    useEffect(() => {
        const interval = setInterval(() => {
            setBullets((prevBullets) =>
                prevBullets
                    .map((bullet) => ({ ...bullet, y: bullet.y - 5 })) // Mermiyi yukarı hareket ettir
                    .filter((bullet) => bullet.y > 0) // Ekranın dışına çıkan mermileri filtrele
            );
        }, 100);
        return () => clearInterval(interval);
    }, []);

    return (
        <Stage width={window.innerWidth * 0.8} height={window.innerHeight * 0.8}>
            <Layer>
                <Background />
                <Spaceship x={spaceshipPosition.x} y={spaceshipPosition.y} />
                {bullets.map((bullet, index) => (
                    <Bullet key={index} x={bullet.x} y={bullet.y} />
                ))}
            </Layer>
        </Stage>
    );
};

export default Game;
